+    #[test]
+    fn days_to_ymd_leap_year() {
+        // 2024-02-29 is a leap day
+        // 2024-01-01 is day 19723
+        // 2024-02-29 is day 19723 + 31 (Jan) + 28 = 19782
+        let (y, m, d) = days_to_ymd(19782);
+        assert_eq!((y, m, d), (2024, 2, 29));
+    }
